// CompletionCost calculate the estimated cost of a completion given a model name and token
// counts.
//
// Returns `None` if the model is not present in the embedded pricing registry.
// Returns `Some(cost_usd)` otherwise, where the value is in US dollars.
//
// When an exact model name match is not found, progressively shorter prefixes
// are tried by stripping from the last `-` or `.` separator.  For example,
// `gpt-4-0613` will match `gpt-4` if no `gpt-4-0613` entry exists.
//
// Example:
//
//	let usd = cost::completion_cost("gpt-4o", 1_000, 500)/* error: gpt-4o is a known model");
//	// 1000 * 0.0000025 + 500 * 0.00001 = 0.0025 + 0.005 = 0.0075
//	assert!((usd - 0.0075).abs() < 1e-9);
func CompletionCost(model string, promptTokens uint64, completionTokens uint64) *float64 {
	cModel := C.CString(model)
	defer C.free(unsafe.Pointer(cModel))

	cPromptTokens := C.uint64_t(uint64(promptTokens))

	cCompletionTokens := C.uint64_t(uint64(completionTokens))

	ptr := C.literllm_completion_cost(cModel, cPromptTokens, cCompletionTokens)
	return func() *float64 { v := float64(ptr); return &v }()
}

// CompletionCostWithCache calculate the estimated cost of a completion, accounting for cached
// (cache-hit) prompt tokens billed at the provider's discounted rate.
//
// `cached_tokens` is the count of prompt tokens served from the provider's
// prompt cache. It must be `<= prompt_tokens` (cached tokens are a subset of
// the prompt). The non-cached portion is billed at `input_cost_per_token`
// and the cached portion at `cache_read_input_token_cost` when the model
// has cache pricing; otherwise the entire prompt is billed at the regular
// input rate.
//
// Returns `None` if the model is not present in the embedded pricing
// registry, mirroring [`completion_cost`].
func CompletionCostWithCache(model string, promptTokens uint64, cachedTokens uint64, completionTokens uint64) *float64 {
	cModel := C.CString(model)
	defer C.free(unsafe.Pointer(cModel))

	cPromptTokens := C.uint64_t(uint64(promptTokens))

	cCachedTokens := C.uint64_t(uint64(cachedTokens))

	cCompletionTokens := C.uint64_t(uint64(completionTokens))

	ptr := C.literllm_completion_cost_with_cache(cModel, cPromptTokens, cCachedTokens, cCompletionTokens)
	return func() *float64 { v := float64(ptr); return &v }()
}

// Clear remove all guardrails from the global registry.
//
// Primarily useful in tests to reset state between test cases.
func Clear() {
	C.literllm_clear()
}

// CountTokens count tokens in a text string using the tokenizer for the given model.
//
// The tokenizer is resolved from the model name prefix (e.g. `"gpt-4o"` maps
// to the `Xenova/gpt-4o` HuggingFace tokenizer). Tokenizers are cached after
// first load.
//
// Errors are returned when returns [`LiterLlmError::BadRequest`] if the tokenizer cannot be loaded
// (e.g. network failure on first use) or if tokenization itself fails.
func CountTokens(model string, text string) (uint, error) {
	cModel := C.CString(model)
	defer C.free(unsafe.Pointer(cModel))

	cText := C.CString(text)
	defer C.free(unsafe.Pointer(cText))

	ptr := C.literllm_count_tokens(cModel, cText)
	if err := lastError(); err != nil {
		return 0, err
	}
	return uint(ptr), nil
}

// CountRequestTokens count tokens for a full [`ChatCompletionRequest`].
//
// Sums tokens across all message text contents plus a per-message overhead
// of ~4 tokens (for role, separators, and formatting metadata). Tool
// definitions and multimodal content parts (images, audio, documents) are
// not counted — only textual content contributes to the token total.
//
// Errors are returned when returns [`LiterLlmError::BadRequest`] if the tokenizer cannot be loaded or
// if tokenization fails for any message.
func CountRequestTokens(model string, req ChatCompletionRequest) (uint, error) {
	cModel := C.CString(model)
	defer C.free(unsafe.Pointer(cModel))

	jsonBytescReq, err := json.Marshal(req)
	if err != nil {
		return 0, fmt.Errorf("failed to marshal: %w", err)
	}
	if string(jsonBytescReq) == "null" {
		jsonBytescReq = []byte("{}")
	}
	tmpStrcReq := C.CString(string(jsonBytescReq))
	cReq := C.literllm_chat_completion_request_from_json(tmpStrcReq)
	C.free(unsafe.Pointer(tmpStrcReq))
	if cReq == nil {
		return 0, fmt.Errorf("failed to create chat_completion_request: %s", C.GoString(C.literllm_last_error_context()))
	}
	defer C.literllm_chat_completion_request_free(cReq)

	ptr := C.literllm_count_request_tokens(cModel, cReq)
	if err := lastError(); err != nil {
		return 0, err
	}
	return uint(ptr), nil
}

// CheckBound assert that `current_len + incoming` does not exceed `limit`.
//
// Call this before appending `incoming` bytes to any buffer that must
// stay below `limit`.  Returns `Err(LiterLlmError::Streaming)` on overflow
// and emits a `tracing::warn!` with context.
//
// Example:
//
//	check_bound("SSE buffer", buffer.len(), chunk.len(), SSE_BUFFER_MAX_BYTES)?;
//	buffer.push_str(chunk_str);
func CheckBound(context string, currentLen uint, incoming uint, limit uint) error {
	cContext := C.CString(context)
	defer C.free(unsafe.Pointer(cContext))

	cCurrentLen := C.size_t(uint(currentLen))

	cIncoming := C.size_t(uint(incoming))

	cLimit := C.size_t(uint(limit))

	C.literllm_check_bound(cContext, cCurrentLen, cIncoming, cLimit)
	return lastError()
}

// EnsureCryptoProvider install the `ring` crypto provider as the rustls process default, idempotently.
//
// rustls 0.23+ removed the implicit default provider. This function installs
// `ring` once per process. Subsequent calls are no-ops. Calling it after
// another rustls crypto provider has already been installed is safe: the
// `Err` from `install_default()` is silently ignored.
//
// Called automatically by every internal `reqwest::Client` constructor
// (auth providers, default HTTP client). Bindings and downstream consumers
// reach those constructors transitively, so no manual init is required.
//
// WASM builds are exempt — the WASM target uses the browser/Node.js fetch
// API instead of rustls, so no crypto provider is needed.
//
// Windows builds use native-tls (SChannel) via reqwest, so rustls is not
// present and no crypto provider installation is needed.
func EnsureCryptoProvider() {
	C.literllm_ensure_crypto_provider()
}

