// ChatStream is a streaming method.
func (h *DefaultClient) ChatStream(req ChatCompletionRequest) (<-chan ChatCompletionChunk, error) {
	jsonBytescReq, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	if string(jsonBytescReq) == "null" {
		jsonBytescReq = []byte("{}")
	}
	tmpStrcReq := C.CString(string(jsonBytescReq))
	cReq := C.literllm_chat_completion_request_from_json(tmpStrcReq)
	C.free(unsafe.Pointer(tmpStrcReq))
	if cReq == nil {
		return nil, fmt.Errorf("failed to create chat_completion_request: %s", C.GoString(C.literllm_last_error_context()))
	}
	defer C.literllm_chat_completion_request_free(cReq)

	handle := C.literllm_default_client_chat_stream_start((*C.LITERLLMDefaultClient)(unsafe.Pointer(h.ptr)), cReq)
	if handle == nil {
		if err := lastError(); err != nil {
			return nil, err
		}
		return nil, fmt.Errorf("failed to start chat_stream stream")
	}
	ch := make(chan ChatCompletionChunk)
	go func() {
		defer close(ch)
		defer C.literllm_default_client_chat_stream_free(handle)
		for {
			chunkPtr := C.literllm_default_client_chat_stream_next(handle)
			if chunkPtr == nil {
				return
			}
			jsonPtr := C.literllm_chat_completion_chunk_to_json(chunkPtr)
			if jsonPtr == nil {
				C.literllm_chat_completion_chunk_free(chunkPtr)
				return
			}
			var chunk ChatCompletionChunk
			unmarshalErr := json.Unmarshal([]byte(C.GoString(jsonPtr)), &chunk)
			C.literllm_free_string(jsonPtr)
			C.literllm_chat_completion_chunk_free(chunkPtr)
			if unmarshalErr != nil {
				return
			}
			ch <- chunk
		}
	}()
	return ch, nil
}

